mapper.select:
SELECT round_no, member_no, pred_num, hit_yn, submit_at, create_ts, update_ts
FROM MEM_PRED_NUM
WHERE round_no  = #{roundNo}
  AND member_no = #{memberNo}

SELECT ra.ranking, COALESCE(m.nickname, m.user_id) AS nickname, p.pred_num AS predNum, p.hit_yn, p.submit_at FROM MEM_PRED_NUM p JOIN MEM_JOIN_INFO m ON m.member_no = p.member_no LEFT JOIN MEM_RANK_ALL ra ON ra.member_no = p.member_no AND ra.round_no = #{roundNo} - 1 WHERE p.round_no = #{roundNo}
ORDER BY (ra.ranking IS NULL) DESC, ra.ranking DESC, p.submit_at ASC
ORDER BY (ra.ranking IS NULL) ASC, ra.ranking ASC, p.submit_at ASC
LIMIT #{pageSize} OFFSET #{offset}

SELECT r5.ranking, COALESCE(m.nickname, m.user_id) AS nickname, p.pred_num AS predNum, p.hit_yn, p.submit_at FROM MEM_PRED_NUM p JOIN MEM_JOIN_INFO m ON m.member_no = p.member_no LEFT JOIN MEM_RANK_5ROUND r5 ON r5.member_no = p.member_no AND r5.round_no = #{roundNo} - 1 WHERE p.round_no = #{roundNo}
ORDER BY (r5.ranking IS NULL) DESC, r5.ranking DESC, p.submit_at ASC
ORDER BY (r5.ranking IS NULL) ASC, r5.ranking ASC, p.submit_at ASC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
  FROM MEM_PRED_NUM p
 WHERE p.round_no = #{roundNo}

SELECT num AS lottoNum, COUNT(*) AS appearCnt, GROUP_CONCAT(rn ORDER BY rn DESC SEPARATOR ',') AS roundList FROM ( SELECT ROUND_NO AS rn, NUM1 AS num FROM LTT_ROUND_RESULT UNION ALL SELECT ROUND_NO, NUM2 FROM LTT_ROUND_RESULT UNION ALL SELECT ROUND_NO, NUM3 FROM LTT_ROUND_RESULT UNION ALL SELECT ROUND_NO, NUM4 FROM LTT_ROUND_RESULT UNION ALL SELECT ROUND_NO, NUM5 FROM LTT_ROUND_RESULT UNION ALL SELECT ROUND_NO, NUM6 FROM LTT_ROUND_RESULT
UNION ALL SELECT ROUND_NO, BONUS_NUM FROM LTT_ROUND_RESULT
) all_nums WHERE rn IN ( SELECT rn2 FROM (SELECT ROUND_NO AS rn2 FROM LTT_ROUND_RESULT ORDER BY ROUND_NO DESC LIMIT #{roundCnt}) t ) GROUP BY num ORDER BY appearCnt DESC, num ASC

SELECT n.n AS lottoNum, (SELECT COUNT(*) FROM LTT_ROUND_RESULT WHERE ROUND_NO > IFNULL( (SELECT MAX(aw.ROUND_NO) FROM ( SELECT NUM1 AS num, ROUND_NO FROM LTT_ROUND_RESULT UNION ALL SELECT NUM2, ROUND_NO FROM LTT_ROUND_RESULT UNION ALL SELECT NUM3, ROUND_NO FROM LTT_ROUND_RESULT UNION ALL SELECT NUM4, ROUND_NO FROM LTT_ROUND_RESULT UNION ALL SELECT NUM5, ROUND_NO FROM LTT_ROUND_RESULT UNION ALL SELECT NUM6, ROUND_NO FROM LTT_ROUND_RESULT
UNION ALL SELECT BONUS_NUM, ROUND_NO FROM LTT_ROUND_RESULT
) aw WHERE aw.num = n.n ), 0 ) ) AS consecutiveAbsent FROM ( SELECT 1 AS n UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9 UNION ALL SELECT 10 UNION ALL SELECT 11 UNION ALL SELECT 12 UNION ALL SELECT 13 UNION ALL SELECT 14 UNION ALL SELECT 15 UNION ALL SELECT 16 UNION ALL SELECT 17 UNION ALL SELECT 18 UNION ALL SELECT 19 UNION ALL SELECT 20 UNION ALL SELECT 21 UNION ALL SELECT 22 UNION ALL SELECT 23 UNION ALL SELECT 24 UNION ALL SELECT 25 UNION ALL SELECT 26 UNION ALL SELECT 27 UNION ALL SELECT 28 UNION ALL SELECT 29 UNION ALL SELECT 30 UNION ALL SELECT 31 UNION ALL SELECT 32 UNION ALL SELECT 33 UNION ALL SELECT 34 UNION ALL SELECT 35 UNION ALL SELECT 36 UNION ALL SELECT 37 UNION ALL SELECT 38 UNION ALL SELECT 39 UNION ALL SELECT 40 UNION ALL SELECT 41 UNION ALL SELECT 42 UNION ALL SELECT 43 UNION ALL SELECT 44 UNION ALL SELECT 45 ) n WHERE n.n NOT IN ( SELECT DISTINCT num FROM ( SELECT NUM1 AS num FROM LTT_ROUND_RESULT WHERE ROUND_NO IN (SELECT rn FROM (SELECT ROUND_NO AS rn FROM LTT_ROUND_RESULT ORDER BY ROUND_NO DESC LIMIT #{roundCnt}) t) UNION ALL SELECT NUM2 FROM LTT_ROUND_RESULT WHERE ROUND_NO IN (SELECT rn FROM (SELECT ROUND_NO AS rn FROM LTT_ROUND_RESULT ORDER BY ROUND_NO DESC LIMIT #{roundCnt}) t) UNION ALL SELECT NUM3 FROM LTT_ROUND_RESULT WHERE ROUND_NO IN (SELECT rn FROM (SELECT ROUND_NO AS rn FROM LTT_ROUND_RESULT ORDER BY ROUND_NO DESC LIMIT #{roundCnt}) t) UNION ALL SELECT NUM4 FROM LTT_ROUND_RESULT WHERE ROUND_NO IN (SELECT rn FROM (SELECT ROUND_NO AS rn FROM LTT_ROUND_RESULT ORDER BY ROUND_NO DESC LIMIT #{roundCnt}) t) UNION ALL SELECT NUM5 FROM LTT_ROUND_RESULT WHERE ROUND_NO IN (SELECT rn FROM (SELECT ROUND_NO AS rn FROM LTT_ROUND_RESULT ORDER BY ROUND_NO DESC LIMIT #{roundCnt}) t) UNION ALL SELECT NUM6 FROM LTT_ROUND_RESULT WHERE ROUND_NO IN (SELECT rn FROM (SELECT ROUND_NO AS rn FROM LTT_ROUND_RESULT ORDER BY ROUND_NO DESC LIMIT #{roundCnt}) t)
UNION ALL SELECT BONUS_NUM FROM LTT_ROUND_RESULT WHERE ROUND_NO IN (SELECT rn FROM (SELECT ROUND_NO AS rn FROM LTT_ROUND_RESULT ORDER BY ROUND_NO DESC LIMIT #{roundCnt}) t)
) appeared ) ORDER BY consecutiveAbsent DESC, n.n ASC
